public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        long[] depths = new long[n];
        for (int i = 0; i < n; i++) {
            depths[i] = computeDepth(nums[i]);
        }

        FenwickTree[] ft = new FenwickTree[6];
        for (int d = 0; d < 6; d++) {
            ft[d] = new FenwickTree(n);
        }

        for (int i = 0; i < n; i++) {
            long d = depths[i];
            if (d < 6) {
                ft[(int) d].update(i + 1, 1);
            }
        }

        long[] answer = new long[queries.length];
        int idx = 0;
        for (long[] q : queries) {
            if (q[0] == 1) {
                int l = (int) q[1];
                int r = (int) q[2];
                int k = (int) q[3];
                if (k < 0 || k >= 6) {
                    answer[idx++] = 0;
                    continue;
                }
                FenwickTree f = ft[k];
                long sum = f.query(r + 1) - f.query(l);
                answer[idx++] = sum;
            } else {
                int idxQ = (int) q[1];
                long val = q[2];
                long oldVal = nums[idxQ];
                long oldDepth = depths[idxQ];
                if (oldDepth < 6) {
                    ft[oldDepth].update(idxQ + 1, -1);
                }
                nums[idxQ] = val;
                long newDepth = computeDepth(val);
                if (newDepth < 6) {
                    ft[newDepth].update(idxQ + 1, 1);
                }
                depths[idxQ] = newDepth;
            }
        }
        return answer;
    }

    static class FenwickTree {
        private int size;
        private long[] tree;

        public FenwickTree(int size) {
            this.size = size;
            this.tree = new long[size + 1];
        }

        public void update(int index, long delta) {
            while (index <= size) {
                tree[index] += delta;
                index += index & -index;
            }
        }

        public long query(int index) {
            long sum = 0;
            while (index > 0) {
                sum += tree[index];
                index -= index & -index;
            }
            return sum;
        }
    }

    private static long computeDepth(long x) {
        long steps = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            steps++;
        }
        return steps;
    }
}
